var input = $input.first().json;
var client = input.client || {};
var project = input.project || {};
var onboard_id = 'OB-' + new Date().getTime();
var folder_name = (client.company || client.name || 'Client') + ' - ' + onboard_id;

return [{
  json: {
    onboard_id: onboard_id,
    client: client,
    project: project,
    folder_name: folder_name,
    timestamp: new Date().toISOString()
  }
}];
